class FreqTree:
    def __init__(self, n):
        self.n = n
        self.bit = [0]*(n+1)
    def add(self, i, delta):
        n = self.n
        while i <= n:
            self.bit[i] += delta
            i += i & -i
    def sum(self, i):
        s = 0
        while i > 0:
            s += self.bit[i]
            i -= i & -i
        return s
    def range_sum(self, l, r):
        if r < l:
            return 0
        return self.sum(r) - self.sum(l-1)

